function.body:
-- Logistice
  v_ResultStr VARCHAR2(2000):='';
  v_Message VARCHAR2(2000):='';
  v_Result NUMBER:=1; -- 0=failure
  v_Record_ID VARCHAR2(32);
  v_User_ID VARCHAR2(32);
  -- Parameter
  TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    -- Parameter Variables

  BEGIN

    FOR Cur_Parameter IN
              ( SELECT i.Record_ID, i.CreatedBy, p.AD_PInstance_ID
				  FROM AD_PInstance i
				  LEFT JOIN AD_PInstance_Para p
				  ON i.AD_PInstance_ID =  p.AD_PInstance_ID
				  WHERE i.AD_PInstance_ID = p_pinstance_id
			   	  ORDER BY p.SeqNo
			  )
    LOOP

     v_Record_ID:=coalesce(Cur_Parameter.Record_ID,'ND');

    END LOOP; -- Get Parameter

	if v_Record_ID <>'ND' then
		--raise exception '%',v_Record_ID;

		create table sspitra_ct_tmp
		as
		select
		* 
		from fin_payment_scheduledetail
		where em_sspitra_ct_detail_id
		in (
		select 
		sspitra_ct_detail_id
			from sspitra_ct_detail where sspitra_collectiontransit_id =  v_Record_ID
		);



		UPDATE sspitra_collectiontransit SET 
		FIN_Payment_ID = null  WHERE sspitra_collectiontransit_id = v_Record_ID;

			create table sspitra_ct_tmp2
			as
			select fpsd.fin_payment_Detail_id
			, fpsd.amount 
			, fpsd.fin_payment_scheduledetail_id
			from fin_payment_scheduledetail fpsd
			join fin_payment_detail fpd on fpd.fin_payment_Detail_id = fpsd.fin_payment_Detail_id
			where fpsd.amount<> fpd.amount
			and exists(
					select 1 from sspitra_ct_tmp sct 
					where  sct.fin_payment_schedule_invoice = fpsd.fin_payment_schedule_invoice
			);

			update fin_payment_scheduledetail set em_sspitra_ct_detail_id = null, fin_payment_detail_id =null where fin_payment_scheduledetail_id in (
				select fin_payment_scheduledetail_id from sspitra_ct_tmp2 
				where fin_payment_detail_id is not null
			);

			update fin_payment_scheduledetail set em_sspitra_ct_detail_id = null  where fin_payment_scheduledetail_id in (
				select fin_payment_scheduledetail_id from sspitra_ct_tmp 
				where em_sspitra_ct_detail_id is not null
			);


			update sspitra_collectiontransit set status='D' where sspitra_collectiontransit_id =v_Record_ID;

			drop table if exists sspitra_ct_tmp;
			drop table if exists sspitra_ct_tmp2;

	end if;

            AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 1, '') ;
  BEGIN --BODY

    RETURN;
  END; --BODY
EXCEPTION
WHEN OTHERS THEN
  v_ResultStr:= '@ERROR=' || SQLERRM;
  DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
  ROLLBACK;
  IF(p_PInstance_ID IS NOT NULL) THEN
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
  END IF;
  RETURN;
END SSPITRA_COLL_UNLINK
